import { createElement } from '../render.js';
import { humanizePointDateTime } from '../utils.js';
import { getOffers } from '../mock/offer.js';
import { EVENT_TYPES } from '../const.js';

const DATE_TIME_FORMAT = 'DD/MM/YY HH:mm';

const createEventTypeListTemplate = (point) =>
  EVENT_TYPES.map(
    (type) =>
      `<div class="event__type-item">
        <input id="event-type-${type}-1"
               class="event__type-input  visually-hidden"
               type="radio"
               name="event-type"
               value="${type}"
               ${point.type === type ? 'checked' : ''}>
        <label class="event__type-label  event__type-label--${type}" for="event-type-${type}-1">${type}</label>
      </div>`,
  ).join(' ');

const createEventOffersTemplate = (point) => {
  const availableOffers = getOffers().find(
    ({ type }) => type === point.type,
  ).offers;

  if (!availableOffers.length) {
    return '';
  }

  const offersList = availableOffers
    .map(({ title, price }) => {
      const inputName = `event-offer-${title.replaceAll(' ', '-').toLowerCase()}`;
      const checkedOffer = point.offers.find((offer) => offer.title === title);

      return `<div class="event__offer-selector">
                <input class="event__offer-checkbox  visually-hidden"
                       id="${inputName}-1"
                       type="checkbox"
                       name="${inputName}"
                       ${checkedOffer ? 'checked' : ''}>
                <label class="event__offer-label" for="${inputName}-1">
                  <span class="event__offer-title">${title}</span>
                  &plus;&euro;&nbsp;
                  <span class="event__offer-price">${price}</span>
                </label>
              </div>`;
    })
    .join(' ');

  return `<section class="event__section  event__section--offers">
            <h3 class="event__section-title  event__section-title--offers">Offers</h3>
            <div class="event__available-offers">${offersList}</div>
          </section>`;
};

const createEditPointTemplate = (point) => {
  const { startDateTime, endDateTime, type, destination } = point;

  return `<li class="trip-events__item">
              <form class="event event--edit" action="#" method="post">
                <header class="event__header">
                  <div class="event__type-wrapper">
                    <label class="event__type  event__type-btn" for="event-type-toggle-1">
                      <span class="visually-hidden">Choose event type</span>
                      <img class="event__type-icon" width="17" height="17" src="img/icons/${type}.png" alt="Event type icon">
                    </label>
                    <input class="event__type-toggle  visually-hidden" id="event-type-toggle-1" type="checkbox">
                    <div class="event__type-list">
                      <fieldset class="event__type-group">
                        <legend class="visually-hidden">Event type</legend>
                        ${createEventTypeListTemplate(point)}
                      </fieldset>
                    </div>
                  </div>
                  <div class="event__field-group  event__field-group--destination">
                    <label class="event__label  event__type-output" for="event-destination-1">
                      ${type}
                    </label>
                    <input class="event__input  event__input--destination" id="event-destination-1" type="text" name="event-destination" value="${destination.title}" list="destination-list-1">
                    <datalist id="destination-list-1">
                      <option value="Amsterdam"></option>
                      <option value="Geneva"></option>
                      <option value="Chamonix"></option>
                    </datalist>
                  </div>
                  <div class="event__field-group  event__field-group--time">
                    <label class="visually-hidden" for="event-start-time-1">From</label>
                    <input class="event__input  event__input--time" id="event-start-time-1" type="text" name="event-start-time" value="${humanizePointDateTime(startDateTime, DATE_TIME_FORMAT)}">
                    &mdash;
                    <label class="visually-hidden" for="event-end-time-1">To</label>
                    <input class="event__input  event__input--time" id="event-end-time-1" type="text" name="event-end-time" value="${humanizePointDateTime(endDateTime, DATE_TIME_FORMAT)}">
                  </div>
                  <div class="event__field-group  event__field-group--price">
                    <label class="event__label" for="event-price-1">
                      <span class="visually-hidden">Price</span>
                      &euro;
                    </label>
                    <input class="event__input  event__input--price" id="event-price-1" type="text" name="event-price" value="${point.price}">
                  </div>
                  <button class="event__save-btn  btn  btn--blue" type="submit">Save</button>
                  <button class="event__reset-btn" type="reset">Delete</button>
                  <button class="event__rollup-btn" type="button">
                    <span class="visually-hidden">Open event</span>
                  </button>
                </header>
                <section class="event__details">
                  ${createEventOffersTemplate(point)}
                  <section class="event__section  event__section--destination">
                    <h3 class="event__section-title  event__section-title--destination">Destination</h3>
                    <p class="event__destination-description">${destination.description}</p>
                  </section>
                </section>
              </form>
            </li>`;
};

export default class EditPointView {
  constructor({ point }) {
    this.point = point;
  }

  getTemplate() {
    return createEditPointTemplate(this.point);
  }

  getElement() {
    if (!this.element) {
      this.element = createElement(this.getTemplate());
    }

    return this.element;
  }

  removeElement() {
    this.element = null;
  }
}
